import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import { API } from "@/App";
import axios from "axios";
import {
  GraduationCap,
  AlertCircle,
  Copy,
  CheckCircle,
} from "lucide-react";
import { Alert, AlertDescription } from "@/components/ui/alert";

const RegisterPage = () => {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    name: "",
    address: "",
    phone: "",
    email: "",
    school_type: "",
    admin_name: "",
    admin_email: "",
    admin_phone: "",
    admin_password: "",
  });

  const [loading, setLoading] = useState(false);

  // =========================
  // GENERATED ACCESS DATA
  // =========================
  const [inviteCode, setInviteCode] = useState("");
  const [joinLink, setJoinLink] = useState("");
  const [registered, setRegistered] = useState(false);

  const updateField = (field, value) => {
    setFormData((prev) => ({
      ...prev,
      [field]: value,
    }));
  };

  // =========================
  // COPY HELPER
  // =========================
  const copyToClipboard = async (text) => {
    try {
      await navigator.clipboard.writeText(text);
      toast.success("Copied successfully");
    } catch {
      toast.error("Failed to copy");
    }
  };

  // =========================
  // REGISTER
  // =========================
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.school_type) {
      toast.error("Please select school type");
      return;
    }

    if (!formData.admin_email || !formData.admin_password) {
      toast.error("Admin email and password are required");
      return;
    }

    setLoading(true);

    try {
      // =========================
      // API CALL
      // =========================
      const response = await axios.post(
        `${API}/auth/register-school`,
        formData
      );

      // =========================
      // EXPECTED BACKEND RESPONSE
      // =========================
      // {
      //   invite_code: "...",
      //   join_link: "..."
      // }
      // =========================

      const data = response.data || {};

      const generatedInviteCode =
        data.invite_code ||
        data.school_invite_code ||
        "";

      const generatedJoinLink =
        data.join_link ||
        `${window.location.origin}/join/${generatedInviteCode}`;

      setInviteCode(generatedInviteCode);
      setJoinLink(generatedJoinLink);

      setRegistered(true);

      toast.success("School registered successfully");

    } catch (error) {
      console.error(error);

      toast.error(
        error?.response?.data?.detail
          ? JSON.stringify(error.response.data.detail)
          : error?.message || "Registration failed"
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0B1120] flex items-center justify-center p-6">
      <Card className="w-full max-w-2xl bg-[#1A2332] border-[#1E3A4F]/40">
        <CardHeader className="text-center space-y-4">
          <div className="mx-auto w-16 h-16 bg-emerald-600 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-600/20">
            <GraduationCap className="w-10 h-10 text-white" />
          </div>

          <div>
            <CardTitle className="text-3xl font-bold text-white">
              School Administrator Registration
            </CardTitle>

            <CardDescription className="text-slate-400 mt-2">
              Only school administrators can create a school account
            </CardDescription>
          </div>
        </CardHeader>

        <CardContent>

          {/* =========================
              SUCCESS SECTION
          ========================= */}
          {registered && (
            <Alert className="mb-6 border-emerald-500/20 bg-emerald-500/10">
              <CheckCircle className="h-4 w-4 text-emerald-400" />

              <AlertDescription className="text-emerald-200 space-y-4">

                <div className="font-semibold text-lg">
                  School Registered Successfully
                </div>

                {/* INVITE CODE */}
                <div>
                  <div className="text-sm mb-1 text-slate-300">
                    School Invite Code
                  </div>

                  <div className="flex gap-2">
                    <Input
                      value={inviteCode}
                      readOnly
                      className="bg-slate-900 text-white"
                    />

                    <Button
                      type="button"
                      onClick={() =>
                        copyToClipboard(inviteCode)
                      }
                    >
                      <Copy className="w-4 h-4" />
                    </Button>
                  </div>
                </div>

                {/* JOIN LINK */}
                <div>
                  <div className="text-sm mb-1 text-slate-300">
                    School Join Link
                  </div>

                  <div className="flex gap-2">
                    <Input
                      value={joinLink}
                      readOnly
                      className="bg-slate-900 text-white"
                    />

                    <Button
                      type="button"
                      onClick={() =>
                        copyToClipboard(joinLink)
                      }
                    >
                      <Copy className="w-4 h-4" />
                    </Button>
                  </div>
                </div>

                <div className="pt-2">
                  <Button
                    type="button"
                    className="w-full"
                    onClick={() => navigate("/login")}
                  >
                    Continue To Login
                  </Button>
                </div>

              </AlertDescription>
            </Alert>
          )}

          <Alert className="mb-6 border-emerald-500/20 bg-emerald-500/10">
            <AlertCircle className="h-4 w-4 text-emerald-400" />

            <AlertDescription className="text-emerald-300">
              Installation Fee: KES 5,000 (one-time) | Monthly Subscription:
              KES 2,000 per school
            </AlertDescription>
          </Alert>

          <form onSubmit={handleSubmit} className="space-y-6">

            <div className="space-y-4">
              <h3 className="font-semibold text-lg text-white">
                School Information
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                <div className="space-y-2">
                  <Label htmlFor="name">School Name</Label>

                  <Input
                    id="name"
                    data-testid="register-school-name"
                    value={formData.name}
                    onChange={(e) =>
                      updateField("name", e.target.value)
                    }
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="school_type">
                    School Type
                  </Label>

                  <Select
                    value={formData.school_type}
                    onValueChange={(value) =>
                      updateField("school_type", value)
                    }
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select school type" />
                    </SelectTrigger>

                    <SelectContent>
                      <SelectItem value="primary">
                        Primary School
                      </SelectItem>

                      <SelectItem value="junior_secondary">
                        Junior Secondary School
                      </SelectItem>

                      <SelectItem value="senior_secondary">
                        Senior Secondary School
                      </SelectItem>

                      <SelectItem value="college">
                        College
                      </SelectItem>

                      <SelectItem value="university">
                        University
                      </SelectItem>
                    </SelectContent>
                  </Select>
                </div>

              </div>

              <div className="space-y-2">
                <Label htmlFor="address">Address</Label>

                <Input
                  id="address"
                  value={formData.address}
                  onChange={(e) =>
                    updateField("address", e.target.value)
                  }
                  required
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                <div className="space-y-2">
                  <Label htmlFor="phone">School Phone</Label>

                  <Input
                    id="phone"
                    value={formData.phone}
                    onChange={(e) =>
                      updateField("phone", e.target.value)
                    }
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="email">School Email</Label>

                  <Input
                    id="email"
                    type="email"
                    value={formData.email}
                    onChange={(e) =>
                      updateField("email", e.target.value)
                    }
                    required
                  />
                </div>

              </div>
            </div>

            <div className="space-y-4">

              <h3 className="font-semibold text-lg text-white">
                Administrator Details
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                <div className="space-y-2">
                  <Label htmlFor="admin_name">
                    Full Name
                  </Label>

                  <Input
                    id="admin_name"
                    value={formData.admin_name}
                    onChange={(e) =>
                      updateField("admin_name", e.target.value)
                    }
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="admin_phone">
                    Phone
                  </Label>

                  <Input
                    id="admin_phone"
                    value={formData.admin_phone}
                    onChange={(e) =>
                      updateField("admin_phone", e.target.value)
                    }
                    required
                  />
                </div>

              </div>

              <div className="space-y-2">
                <Label htmlFor="admin_email">
                  Email
                </Label>

                <Input
                  id="admin_email"
                  type="email"
                  value={formData.admin_email}
                  onChange={(e) =>
                    updateField("admin_email", e.target.value)
                  }
                  required
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="admin_password">
                  Password
                </Label>

                <Input
                  id="admin_password"
                  type="password"
                  value={formData.admin_password}
                  onChange={(e) =>
                    updateField("admin_password", e.target.value)
                  }
                  required
                />
              </div>

            </div>

            <Button
              type="submit"
              className="w-full"
              disabled={loading}
            >
              {loading
                ? "Registering..."
                : "Register School"}
            </Button>

          </form>

          <div className="mt-6 text-center text-sm text-slate-500">
            Teachers, finance staff, secretaries, parents and students
            should receive an invite link or school code from the
            school administrator.
          </div>

        </CardContent>
      </Card>
    </div>
  );
};

export default RegisterPage;
